import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import MembershipCard from '../components/MembershipCard';
import { useAuth } from '../context/AuthContext';
import api from '../services/api';
import { FaCheck } from 'react-icons/fa';
import './Membership.css';

const Membership = () => {
  const [memberships, setMemberships] = useState([]);
  const [loading, setLoading] = useState(true);
  const { user } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    const fetchMemberships = async () => {
      try {
        const response = await api.get('/memberships');
        setMemberships(response.data);
      } catch (error) {
        toast.error('Failed to load memberships');
      } finally {
        setLoading(false);
      }
    };
    fetchMemberships();
  }, []);

  const handleSubscribe = async (membershipId) => {
    if (!user) {
      toast.info('Please login to subscribe');
      navigate('/login');
      return;
    }

    try {
      await api.post(`/memberships/${membershipId}/subscribe`);
      toast.success('Successfully subscribed to membership!');
      navigate('/dashboard');
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to subscribe');
    }
  };

  const benefits = [
    'Access to all gym equipment',
    'Free fitness assessment',
    'Locker room access',
    'Free parking',
    'Mobile app access',
    'Guest passes',
    'Nutrition consultation',
    'Priority class booking'
  ];

  return (
    <div className="membership-page">
      {/* Hero Section */}
      <section className="membership-hero">
        <div className="hero-overlay"></div>
        <div className="container">
          <h1>Membership <span>Plans</span></h1>
          <p>Choose the perfect plan for your fitness journey</p>
        </div>
      </section>

      {/* Membership Plans */}
      <section className="section">
        <div className="container">
          {loading ? (
            <div className="loading">
              <div className="spinner"></div>
            </div>
          ) : (
            <div className="grid grid-3">
              {memberships.map((membership) => (
                <MembershipCard 
                  key={membership._id} 
                  membership={membership}
                  onSubscribe={handleSubscribe}
                />
              ))}
            </div>
          )}
        </div>
      </section>

      {/* All Benefits Section */}
      <section className="section benefits-section">
        <div className="container">
          <div className="section-title">
            <h2>All Memberships <span>Include</span></h2>
            <p>Every membership comes with these amazing benefits</p>
          </div>
          <div className="benefits-grid">
            {benefits.map((benefit, index) => (
              <div key={index} className="benefit-item">
                <FaCheck className="check-icon" />
                <span>{benefit}</span>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* FAQ Section */}
      <section className="section faq-section">
        <div className="container">
          <div className="section-title">
            <h2>Frequently Asked <span>Questions</span></h2>
          </div>
          <div className="faq-list">
            <div className="faq-item">
              <h3>Can I cancel my membership anytime?</h3>
              <p>
                Yes, you can cancel your membership at any time. However, please 
                note that cancellation must be done 7 days before your next billing cycle.
              </p>
            </div>
            <div className="faq-item">
              <h3>Can I freeze my membership?</h3>
              <p>
                Yes, you can freeze your membership for up to 3 months per year. 
                Contact our support team to arrange this.
              </p>
            </div>
            <div className="faq-item">
              <h3>Is there a joining fee?</h3>
              <p>
                There's no joining fee! Just pay for your chosen membership plan 
                and start working out immediately.
              </p>
            </div>
            <div className="faq-item">
              <h3>Can I bring a guest?</h3>
              <p>
                Premium and Elite members can bring guests. Basic members can 
                purchase day passes for guests.
              </p>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Membership;
